if not _pango_available:
    import warnings
    warnings.warn(f"ManimPango native libs: {_pango_error or 'unknown error'}", stacklevel=2)

    # ═══════════════════════════════════════════════════════════════
    # Complete manimpango API reimplementation using pycairo
    # Matches all classes, functions, and parameters from the real
    # manimpango 0.6.1 (Pango+Cairo Cython bindings)
    # ═══════════════════════════════════════════════════════════════

    from enum import IntEnum as _IntEnum

    class Style(_IntEnum):
        NORMAL = 0
        ITALIC = 1
        OBLIQUE = 2

    class Weight(_IntEnum):
        THIN = 100
        ULTRALIGHT = 200
        LIGHT = 300
        BOOK = 380
        NORMAL = 400
        MEDIUM = 500
        SEMIBOLD = 600
        BOLD = 700
        ULTRABOLD = 800
        HEAVY = 900
        ULTRAHEAVY = 1000

    class Variant(_IntEnum):
        NORMAL = 0
        SMALL_CAPS = 1

    class Alignment(_IntEnum):
        LEFT = 0
        CENTER = 1
        RIGHT = 2

    class PangoUtils:
        _STYLE_MAP = {'NORMAL': Style.NORMAL, 'ITALIC': Style.ITALIC, 'OBLIQUE': Style.OBLIQUE}
        _WEIGHT_MAP = {
            'NORMAL': Weight.NORMAL, 'BOLD': Weight.BOLD, 'THIN': Weight.THIN,
            'ULTRALIGHT': Weight.ULTRALIGHT, 'LIGHT': Weight.LIGHT, 'BOOK': Weight.BOOK,
            'MEDIUM': Weight.MEDIUM, 'SEMIBOLD': Weight.SEMIBOLD,
            'ULTRABOLD': Weight.ULTRABOLD, 'HEAVY': Weight.HEAVY, 'ULTRAHEAVY': Weight.ULTRAHEAVY,
        }

        @staticmethod
        def str2style(s):
            return PangoUtils._STYLE_MAP.get(str(s).upper(), Style.NORMAL)

        @staticmethod
        def str2weight(s):
            return PangoUtils._WEIGHT_MAP.get(str(s).upper(), Weight.NORMAL)

        @staticmethod
        def remove_last_M(file_path):
            """Remove trailing 'M' from SVG path data (Pango artifact)."""
            if not file_path or not os.path.exists(str(file_path)):
                return file_path
            try:
                with open(str(file_path), 'r') as f:
                    content = f.read()
                # Remove trailing M commands that Pango sometimes adds
                import re
                content = re.sub(r'M\s*"', '"', content)
                with open(str(file_path), 'w') as f:
                    f.write(content)
            except Exception:
                pass
            return file_path

    class TextSetting:
        """Formatting for slices of a Text object (matches real manimpango)."""
        def __init__(self, start=0, end=0, font='', slant='NORMAL', weight='NORMAL',
                     line_num=-1, color=None, is_new_line=False, **kwargs):
            self.start = int(start)
            self.end = int(end)
            self.font = str(font) if font else ''
            self.slant = str(slant) if slant else 'NORMAL'
            self.weight = str(weight) if weight else 'NORMAL'
            self.line_num = int(line_num) if line_num is not None else -1
            self.color = color
            self.is_new_line = is_new_line

    class RegisteredFont:
        def __init__(self, path='', type=''):
            self.path = str(path)
            self.type = str(type)

    registered_fonts = set()

    def register_font(font_path):
        registered_fonts.add(RegisteredFont(str(font_path)))
        return True

    def unregister_font(font_path):
        return True

    def list_fonts():
        return []

    # ── Color parsing helper ──
    def _parse_color(color_str):
        """Parse a color string (#hex or named) to (r, g, b) floats 0-1."""
        if not color_str or not isinstance(color_str, str):
            return (1.0, 1.0, 1.0)
        c = color_str.strip()
        if c.startswith('#') and len(c) >= 7:
            try:
                return (int(c[1:3], 16)/255.0, int(c[3:5], 16)/255.0, int(c[5:7], 16)/255.0)
            except ValueError:
                pass
        # Named colors (subset)
        _names = {'white':(1,1,1), 'black':(0,0,0), 'red':(1,0,0), 'green':(0,0.5,0),
                  'blue':(0,0,1), 'yellow':(1,1,0), 'cyan':(0,1,1), 'magenta':(1,0,1),
                  'orange':(1,0.65,0), 'purple':(0.5,0,0.5), 'gold':(1,0.84,0)}
        return _names.get(c.lower(), (1.0, 1.0, 1.0))

    # ── Cairo font mapping ──
    def _get_cairo_slant(slant_str):
        import cairo
        s = str(slant_str).upper()
        if s == 'ITALIC': return cairo.FONT_SLANT_ITALIC
        if s == 'OBLIQUE': return cairo.FONT_SLANT_OBLIQUE
        return cairo.FONT_SLANT_NORMAL

    def _get_cairo_weight(weight_str):
        import cairo
        w = str(weight_str).upper()
        if w in ('BOLD', 'ULTRABOLD', 'HEAVY', 'ULTRAHEAVY', 'SEMIBOLD'):
            return cairo.FONT_WEIGHT_BOLD
        return cairo.FONT_WEIGHT_NORMAL

    def text2svg(settings, size, line_spacing, disable_liga, file_name,
                 START_X=0, START_Y=0, width=600, height=400, orig_text='',
                 pango_width=None):
        """Render text to SVG in the same shape real Pango produces:
        a ``<defs>`` block defining each unique glyph path once, plus
        one ``<use>`` per character positioned in place.

        Why this structure matters on iOS:
          • `ctx.text_path(longstring) + ctx.fill()` into an SVGSurface
            fuses every glyph into ONE enormous <path> element with
            thousands of bezier points. Manim parses that as ONE
            VMobject, and every animation frame interpolates the
            entire thing. With 30+ Text mobjects in a scene, this is
            the dominant memory hog that tips the jetsam limit.
          • Real Pango/dvisvgm output defines each glyph once and
            references it via <use>. svgelements + manim then build
            N small VMobjects (one per character) — much lighter to
            interpolate and much friendlier to memory.

        We keep per-character glyph paths in the module-level cache
        `_GLYPH_PATH_CACHE` so the same character (e.g. space, 'e',
        't') is only traced via Cairo once per process.
        """
        import os
        text = str(orig_text) if orig_text else " "
        font_size = float(size) if size else 12.0

        if file_name:
            os.makedirs(os.path.dirname(str(file_name)) or '.', exist_ok=True)
            svg_path = str(file_name)
        else:
            import tempfile
            svg_path = os.path.join(tempfile.gettempdir(), 'manim_text.svg')

        try:
            import cairo

            # Measurement + path-extraction context (1×1 dummy surface).
            meas = cairo.ImageSurface(cairo.FORMAT_ARGB32, 1, 1)
            mctx = cairo.Context(meas)

            PATH_MOVE_TO = cairo.PATH_MOVE_TO
            PATH_LINE_TO = cairo.PATH_LINE_TO
            PATH_CURVE_TO = cairo.PATH_CURVE_TO
            PATH_CLOSE_PATH = cairo.PATH_CLOSE_PATH

            def _extract_glyph_path(ch, font_family, slant, weight, fs):
                """Return SVG path-data string for glyph `ch` placed at
                the origin (x=0, baseline y=0). Caches across calls."""
                cache_key = (ch, font_family, slant, weight, fs)
                cached = _GLYPH_PATH_CACHE.get(cache_key)
                if cached is not None:
                    return cached
                mctx.select_font_face(font_family, slant, weight)
                mctx.set_font_size(fs)
                mctx.new_path()
                mctx.move_to(0.0, 0.0)
                try:
                    mctx.text_path(ch)
                except Exception:
                    _GLYPH_PATH_CACHE[cache_key] = ""
                    return ""
                try:
                    path_data = mctx.copy_path()
                except Exception:
                    path_data = []
                parts = []
                for entry in path_data:
                    ptype, pts = entry[0], entry[1]
                    if ptype == PATH_MOVE_TO:
                        parts.append(f"M{pts[0]:.2f} {pts[1]:.2f}")
                    elif ptype == PATH_LINE_TO:
                        parts.append(f"L{pts[0]:.2f} {pts[1]:.2f}")
                    elif ptype == PATH_CURVE_TO:
                        parts.append(
                            f"C{pts[0]:.2f} {pts[1]:.2f} "
                            f"{pts[2]:.2f} {pts[3]:.2f} "
                            f"{pts[4]:.2f} {pts[5]:.2f}"
                        )
                    elif ptype == PATH_CLOSE_PATH:
                        parts.append("Z")
                d = " ".join(parts)
                _GLYPH_PATH_CACHE[cache_key] = d
                return d

            def _advance_for(ch, font_family, slant, weight, fs):
                mctx.select_font_face(font_family, slant, weight)
                mctx.set_font_size(fs)
                return mctx.text_extents(ch).x_advance

            # Collect unique glyph definitions + per-character placements.
            # Per-SVG scope: d_to_local_id maps a path-data string to the
            # glyph id we assigned inside THIS svg's <defs>. Don't share
            # ids across svgs — each svg must be self-contained.
            defs = {}           # local glyph_id → path-data
            d_to_local_id = {}  # path-data → local glyph_id (dedupe within svg)
            uses = []           # list of (glyph_id_str, x, y, color_hex)
            offset_x = 0.0
            last_line_num = 0

            def _rgb_hex(color_str):
                r, g, b = _parse_color(color_str)
                return f"#{int(round(r*255)):02x}{int(round(g*255)):02x}{int(round(b*255)):02x}"

            for setting in (settings or []):
                font_family = setting.font or "sans-serif"
                cslant = _get_cairo_slant(setting.slant)
                cweight = _get_cairo_weight(setting.weight)
                color = _rgb_hex(setting.color)

                if setting.line_num != last_line_num:
                    offset_x = 0.0
                    last_line_num = setting.line_num

                y_pos = (float(START_Y)
                         + float(line_spacing) * setting.line_num
                         + font_size)
                x_pos = float(START_X) + offset_x

                chunk = text[setting.start:setting.end].replace("\n", " ")
                if not chunk:
                    continue

                for ch in chunk:
                    adv = _advance_for(ch, font_family, cslant, cweight, font_size)
                    if ch.strip():
                        d = _extract_glyph_path(ch, font_family, cslant, cweight, font_size)
                        if d:
                            gid = d_to_local_id.get(d)
                            if gid is None:
                                gid = f"g{len(defs)}"
                                d_to_local_id[d] = gid
                                defs[gid] = d
                            uses.append((gid, x_pos, y_pos, color))
                    x_pos += adv
                    offset_x += adv

            # Assemble SVG. Three important details for correct
            # rendering via svgelements (what manim uses to re-parse
            # this and build VMobjects):
            #
            # 1. fill-rule="nonzero" on each path — Cairo's copy_path
            #    winds glyphs using the even-odd rule by default; if we
            #    don't pin the fill rule explicitly, svgelements picks
            #    a different default and interior holes in glyphs like
            #    'e', 'o', 'a' invert (solid letters become rings).
            # 2. Each <use> carries BOTH a concrete fill AND
            #    fill-opacity="1" — svgelements cascades fills through
            #    <use> inconsistently if the target path has no fill
            #    attribute. Forcing both avoids "invisible text" when
            #    a renderer chooses not to cascade.
            # 3. viewBox — gives svgelements an unambiguous user-space
            #    size. Without it, the parser sometimes falls back to
            #    (0,0,100,100) for the viewport and everything
            #    renders at ~1% size (looks like empty canvas).
            parts = [
                f'<svg xmlns="http://www.w3.org/2000/svg" '
                f'xmlns:xlink="http://www.w3.org/1999/xlink" '
                f'width="{width}" height="{height}" '
                f'viewBox="0 0 {width} {height}">',
                '<defs>',
            ]
            for gid, d in defs.items():
                # fill="currentColor" means the <use>'s fill attribute
                # cascades onto this path. Combined with fill-rule,
                # glyphs render as solid shapes with correct holes.
                parts.append(
                    f'<path id="{gid}" d="{d}" '
                    f'fill="currentColor" fill-rule="nonzero"/>'
                )
            parts.append('</defs>')
            for gid, x, y, color in uses:
                parts.append(
                    f'<use xlink:href="#{gid}" '
                    f'transform="translate({x:.2f},{y:.2f})" '
                    f'color="{color}" fill="{color}" fill-opacity="1"/>'
                )
            parts.append('</svg>')

            svg_bytes = ''.join(parts)
            with open(svg_path, 'w', encoding='utf-8') as f:
                f.write(svg_bytes)

            # Diagnostic dump on first call per process — lets the user
            # inspect the SVG output from the fallback and verify that
            # the text is at least reaching the renderer. Overwrite-in-
            # place so the file never grows unbounded.
            global _DIAG_DUMP_COUNT
            try:
                _DIAG_DUMP_COUNT
            except NameError:
                _DIAG_DUMP_COUNT = 0
            if _DIAG_DUMP_COUNT < 3:
                try:
                    import tempfile as _tf
                    dump = os.path.join(_tf.gettempdir(),
                                        f"manim_text_dump_{_DIAG_DUMP_COUNT}.svg")
                    with open(dump, 'w', encoding='utf-8') as _df:
                        _df.write(svg_bytes)
                    print(f"[manimpango] dumped text2svg output → {dump}  "
                          f"({len(text)}ch, {len(defs)} unique glyphs, "
                          f"{len(uses)} placements)", flush=True)
                    _DIAG_DUMP_COUNT += 1
                except OSError:
                    pass
            meas.finish()
            return svg_path

        except ImportError:
            # Cairo not available — minimal SVG fallback.
            esc = text.replace('&','&amp;').replace('<','&lt;').replace('>','&gt;')
            svg = (f'<svg xmlns="http://www.w3.org/2000/svg" width="{width}" height="{height}">'
                   f'<text x="{START_X}" y="{font_size}" font-size="{font_size}" fill="white">{esc}</text></svg>')
            with open(svg_path, 'w') as f:
                f.write(svg)
            return svg_path

    # Module-level glyph path cache — same character, same font, same
    # size → same path-data string. Per-SVG dedup happens via the
    # d_to_local_id dict inside text2svg.
    _GLYPH_PATH_CACHE: dict = {}

    def markup2svg(text, font='', slant='NORMAL', weight='NORMAL', size=1,
                   _placeholder=None, disable_ligatures=False, file_name='',
                   START_X=0, START_Y=0, width=600, height=400, **kwargs):
        """Render markup text to SVG (strips markup tags, delegates to text2svg)."""
        import re
        plain = re.sub(r'<[^>]+>', '', str(text))
        settings = [TextSetting(start=0, end=len(plain), font=font, slant=slant,
                                weight=weight, color='white')]
        return text2svg(settings, size, 0, disable_ligatures, file_name,
                       START_X, START_Y, width, height, plain)

    class MarkupUtils:
        @staticmethod
        def validate(markup):
            """Validate Pango markup. Returns empty string (valid) on iOS."""
            return ""

        @staticmethod
        def text2svg(text, font=None, slant='NORMAL', weight='NORMAL', size=1,
                     _placeholder=None, disable_liga=False, file_name='',
                     START_X=0, START_Y=0, width=600, height=400, *,
                     justify=None, indent=None, line_spacing=None,
                     alignment=None, pango_width=None):
            """Render Pango markup to SVG via Cairo (same as text2svg)."""
            import re
            plain = re.sub(r'<[^>]+>', '', str(text))
            settings = [TextSetting(start=0, end=len(plain), font=font or '',
                                    slant=slant, weight=weight, color='white')]
            return text2svg(settings, size, line_spacing or 0, disable_liga, file_name,
                           START_X, START_Y, width, height, plain,
                           pango_width=pango_width)

    def pango_version():
        return "1.50.0"

    def cairo_version():
        try:
            import cairo
            return cairo.cairo_version_string()
        except Exception:
            return "1.16.0"

